solutions.python:
def parseMediaQuery(self, s: str) -> list:
    conditions = s.split(' and ')
    sortedConditions = sorted(conditions, key=lambda x: ('min-' in x, 'max-' in x, x.count('and'), x.count('or')))
    return sortedConditions;
